```ts
try {
  const pending = await window.api.settings.get(user.id, 'profile_sync_pending')
  if (pending === 'true') {
    const localUser2 = await window.api.users.findById(user.id)
    if (localUser2 !== null) {
      const dn = localUser2.display_name ?? ''
